import { RunReport } from '../types';

/**
 * Fetches the list of run JSON files from the data directory.
 * In dev mode, Vite serves files from the filesystem.
 * This file listing is done via a generated manifest or API endpoint.
 *
 * For the dev/local workflow, we scan /data via a virtual manifest.
 * The manifest is generated by the json-reporter after each run.
 */

const DATA_BASE = '/data';
const MANIFEST_PATH = `${DATA_BASE}/manifest.json`;

export async function fetchRunManifest(): Promise<string[]> {
  try {
    const res = await fetch(MANIFEST_PATH);
    if (!res.ok) return [];
    const json = await res.json() as { runs: string[] };
    return json.runs ?? [];
  } catch {
    return [];
  }
}

export async function fetchRun(filename: string): Promise<RunReport | null> {
  try {
    const res = await fetch(`${DATA_BASE}/${filename}`);
    if (!res.ok) return null;
    return await res.json() as RunReport;
  } catch {
    return null;
  }
}

export async function fetchAllRuns(): Promise<RunReport[]> {
  const filenames = await fetchRunManifest();
  const runs = await Promise.all(filenames.map(fetchRun));
  return runs
    .filter((r): r is RunReport => r !== null)
    .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
}

export function getFailedTests(runs: RunReport[]) {
  return runs.flatMap((run) =>
    run.tests
      .filter((t) => t.status === 'failed' || t.status === 'timedOut')
      .map((t) => ({ ...t, runId: run.runId, runStartTime: run.startTime }))
  );
}

export function getMatrixData(runs: RunReport[]) {
  // Extract matrix test results grouped by currency/locale
  const latest = runs[0];
  if (!latest) return [];

  return latest.tests
    .filter((t) => t.title.includes('Matrix') || t.title.includes('currency='))
    .map((t) => {
      const currencyMatch = t.title.match(/currency=(\w+)/);
      const langMatch = t.title.match(/lang=(\w+)/);
      return {
        currency: currencyMatch?.[1] ?? 'unknown',
        lang: langMatch?.[1] ?? 'unknown',
        status: t.status,
        title: t.title,
        durationMs: t.durationMs,
      };
    });
}
